import sys

def main():
    import bisect
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    M = int(data[1])
    A = list(map(int, data[2:2+M]))

    res = [0] * N
    for i in range(1, N+1):
        idx = bisect.bisect_left(A, i)
        if idx < M:
            res[i-1] = A[idx] - i
        else:
            res[i-1] = 0

    for val in res:
        print(val)

if __name__ == "__main__":
    main()
